import json
from pathlib import Path

# Read the candidates
input_file = Path("working/wiki/pass2-buckets/characters-house-frey-t-z/prose-edge-candidates-enriched/walda-frey-daughter-of-merrett.candidates.jsonl")
output_file = Path("working/wiki/pass2-buckets/characters-house-frey-t-z/prose-edges-haiku/walda-frey-daughter-of-merrett.edges.jsonl")
output_file.parent.mkdir(parents=True, exist_ok=True)

candidates = []
with open(input_file) as f:
    for line in f:
        candidates.append(json.loads(line))

# Classify each candidate
edges = []

for cand in candidates:
    source = cand.get("source_slug")
    target = cand.get("target_slug")
    target_type = cand.get("target_type")
    evidence = cand.get("evidence_paragraph", "")
    valid_types = cand.get("valid_edge_types", [])
    staging_verbs = cand.get("staging_verbs_present", [])
    section = cand.get("source_section", "")
    anchor = cand.get("anchor_text", "")

    # Strategy: Look at the actual text around the anchor
    # and decide if there's a real relationship

    decision = None
    edge_type = None
    qualifier = None
    confidence = 1
    reason = None

    # Extract context around the anchor
    try:
        if anchor in evidence:
            start = max(0, evidence.find(anchor) - 150)
            end = min(len(evidence), evidence.find(anchor) + 150)
            context = evidence[start:end]
        else:
            context = evidence[:300]
    except:
        context = evidence[:300]

    # KEY RULE 1: Reject mentions that aren't about source
    # If the anchor appears but source isn't a participant in that action, reject
    if "roose" in context.lower() and "walda" not in context.lower():
        # This is about Roose, not Walda's action
        if target not in ["roose-bolton", "ramsay-bolton", "ramsay-snow"]:
            decision = "reject_just_mention"
            reason = "mentioned-in-other-character-action"

    # KEY RULE 2: Family relationships
    elif "stepson" in context.lower() and target_type == "character.human":
        if "STEP_PARENT_OF" in valid_types:
            decision = "emit_edge"
            edge_type = "STEP_PARENT_OF"
    elif "kin" in context.lower() and target_type == "character.human" and "SIBLING_OF" in valid_types:
        if not any(name in target.lower() for name in ["arya", "ramsay", "theon"]):
            decision = "emit_edge"
            edge_type = "SIBLING_OF"
            qualifier = "unknown"

    # KEY RULE 3: Encounters with explicit verb
    elif staging_verbs and target_type == "character.human":
        if "meets" in str(staging_verbs).lower() and "ENCOUNTERS" in valid_types:
            decision = "emit_edge"
            edge_type = "ENCOUNTERS"

    # KEY RULE 4: Weddings and ceremonies
    elif "weds" in context.lower() or "wedding" in target.lower():
        if "walda" in source.lower() and target_type.startswith("event."):
            if "ATTENDS" in valid_types:
                decision = "emit_edge"
                edge_type = "ATTENDS"
        elif target_type == "character.human" and ("weds" in context.lower() and ("roose" in target.lower() or "bolton" in target.lower())):
            if "SPOUSE_OF" in valid_types:
                decision = "emit_edge"
                edge_type = "SPOUSE_OF"
                qualifier = "current"

    # KEY RULE 5: Locations
    elif target_type == "place.location":
        if "at" in context.lower() or "in" in context.lower() or "hold" in context.lower():
            if "LOCATED_AT" in valid_types:
                decision = "emit_edge"
                edge_type = "LOCATED_AT"

    # KEY RULE 6: Travel companions
    elif "travel" in context.lower() and target_type == "character.human":
        if "TRAVELS_WITH" in valid_types and any(name in target.lower() for name in ["frey", "hosteen", "aenys"]):
            decision = "emit_edge"
            edge_type = "TRAVELS_WITH"

    # KEY RULE 7: Concepts and titles - usually just mentions
    elif target_type in ["concept.custom", "concept.theory", "title"]:
        decision = "reject_just_mention"
        reason = "concept-or-title-mention-not-edge"

    # KEY RULE 8: Characters mentioned incidentally
    elif target_type == "character.human" and any(char in target.lower() for char in ["arya", "theon", "jeyne", "lannister"]):
        decision = "reject_just_mention"
        reason = "character-mentioned-in-narrative-not-directly-related"

    # DEFAULT: Try to find an edge type
    if not decision:
        if not valid_types:
            decision = "reject_just_mention"
            reason = "no-valid-edge-types"
        elif target_type == "character.human":
            # Pick a safe default for character-character relationships
            for etype in ["TRAVELS_WITH", "MEMBER_OF", "ALLIES_WITH"]:
                if etype in valid_types:
                    decision = "emit_edge"
                    edge_type = etype
                    confidence = 2
                    break
        elif target_type == "place.location":
            if "LOCATED_AT" in valid_types:
                decision = "emit_edge"
                edge_type = "LOCATED_AT"
                confidence = 2

        if not decision:
            decision = "reject_just_mention"
            reason = "no-clear-relationship-determined"

    # Build the output row
    if decision == "emit_edge":
        row = {
            "decision": "emit_edge",
            "candidate_kind": cand.get("candidate_kind"),
            "evidence_kind": "wiki-entity",
            "source_slug": source,
            "target_slug": target,
            "edge_type": edge_type,
            "confidence_tier": confidence,
            "evidence_snippet": evidence[:200] if evidence else "",
            "evidence_section": section,
            "evidence_paragraph_index": cand.get("source_paragraph_index", 0),
        }
        if qualifier:
            row["qualifier"] = qualifier
    else:
        row = {
            "decision": "reject_just_mention",
            "candidate_kind": cand.get("candidate_kind"),
            "source_slug": source,
            "target_slug": target,
            "reason": reason or "undetermined"
        }

    edges.append(row)

# Write output
with open(output_file, 'w') as f:
    for edge in edges:
        f.write(json.dumps(edge) + "\n")

print(f"[done] walda-frey-daughter-of-merrett.candidates.jsonl → {len([e for e in edges if e['decision']=='emit_edge'])} emit_edge, {len([e for e in edges if e['decision']=='reject_just_mention'])} reject_just_mention, 0 escalate — wrote {output_file}")
